import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);
  const [search, setSearch] = useState("");
  const [slots, setSlots] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/auth/workers")
      .then((res) => setWorkers(res.data));
  }, []);

  const bookWorker = async (worker) => {

    await axios.post(
      "http://localhost:5000/api/jobs/create",
      {
        labourId: worker._id,
        workerName: worker.name,
        workType: worker.skills?.join(", "),
        price: worker.price,
        timeSlots: slots
      }
    );

    alert("Booking Request Sent");
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <div style={styles.headerBox}>

          <div>
            <h1 style={styles.heading}>
              Find Skilled Workers
            </h1>

            <p style={styles.subText}>
              Search and book trusted workers instantly.
            </p>
          </div>

          <div style={styles.statsCard}>
            <h3>Total Workers</h3>
            <p>{workers.length}</p>
          </div>

        </div>

        <div style={styles.filterBox}>

          <input
            style={styles.searchInput}
            placeholder="Search by skill..."
            onChange={(e) => setSearch(e.target.value)}
          />

        </div>

        <div style={styles.slotSection}>

          <h3>Select Preferred Time Slots</h3>

          <div style={styles.slotGrid}>

            <input
              style={styles.slotInput}
              placeholder="Time Slot 1"
              onChange={(e) => setSlots([e.target.value])}
            />

            <input
              style={styles.slotInput}
              placeholder="Time Slot 2"
              onChange={(e) =>
                setSlots([...slots, e.target.value])
              }
            />

            <input
              style={styles.slotInput}
              placeholder="Time Slot 3"
              onChange={(e) =>
                setSlots([...slots, e.target.value])
              }
            />

            <input
              style={styles.slotInput}
              placeholder="Time Slot 4"
              onChange={(e) =>
                setSlots([...slots, e.target.value])
              }
            />

          </div>

        </div>

        <div style={styles.grid}>

          {workers
            .filter((worker) =>
              worker.skills
                ?.join(" ")
                .toLowerCase()
                .includes(search.toLowerCase())
            )
            .map((worker) => (

              <div key={worker._id} style={styles.card}>

                <div style={styles.topRow}>

                  <div style={styles.avatar}>
                    {worker.name?.charAt(0)}
                  </div>

                  <div>
                    <h2>{worker.name}</h2>

                    <p style={styles.role}>
                      Professional Worker
                    </p>
                  </div>

                </div>

                <div style={styles.infoBox}>

                  <p>
                    <strong>Skills:</strong>
                  </p>

                  <div style={styles.skillWrap}>

                    {worker.skills?.map((skill, index) => (
                      <span key={index} style={styles.skill}>
                        {skill}
                      </span>
                    ))}

                  </div>

                </div>

                <div style={styles.priceBox}>

                  <h3>₹ {worker.price}</h3>

                  <p>Per Day</p>

                </div>

                <button
                  style={styles.bookBtn}
                  onClick={() => bookWorker(worker)}
                >
                  Book Worker
                </button>

              </div>
            ))}

        </div>

      </div>

      <Footer />

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px"
  },

  headerBox: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "30px"
  },

  heading: {
    fontSize: "38px",
    color: "#111827"
  },

  subText: {
    color: "#6b7280"
  },

  statsCard: {
    background: "white",
    padding: "20px",
    borderRadius: "16px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.08)",
    textAlign: "center",
    width: "180px"
  },

  filterBox: {
    marginBottom: "30px"
  },

  searchInput: {
    width: "350px",
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #ddd",
    fontSize: "15px"
  },

  slotSection: {
    background: "white",
    padding: "25px",
    borderRadius: "18px",
    marginBottom: "30px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.06)"
  },

  slotGrid: {
    display: "grid",
    gridTemplateColumns: "repeat(2,1fr)",
    gap: "15px",
    marginTop: "20px"
  },

  slotInput: {
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #ddd"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(320px,1fr))",
    gap: "25px"
  },

  card: {
    background: "white",
    borderRadius: "20px",
    padding: "25px",
    boxShadow: "0 10px 25px rgba(0,0,0,0.08)"
  },

  topRow: {
    display: "flex",
    alignItems: "center",
    gap: "15px"
  },

  avatar: {
    width: "60px",
    height: "60px",
    borderRadius: "50%",
    background: "#2563eb",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontSize: "24px",
    fontWeight: "bold"
  },

  role: {
    color: "#6b7280"
  },

  infoBox: {
    marginTop: "20px"
  },

  skillWrap: {
    display: "flex",
    flexWrap: "wrap",
    gap: "10px",
    marginTop: "10px"
  },

  skill: {
    background: "#e0edff",
    color: "#2563eb",
    padding: "8px 12px",
    borderRadius: "20px",
    fontSize: "14px"
  },

  priceBox: {
    marginTop: "25px"
  },

  bookBtn: {
    width: "100%",
    marginTop: "20px",
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "14px",
    borderRadius: "10px",
    fontSize: "15px",
    cursor: "pointer"
  }
};
